static int extended_gcd_impl(int a, int b, int *x, int *y) {
    if (a == 0) {
        *x = 0;
        *y = 1;
        return b;
    }

    int x1 = 0;
    int y1 = 0;
    int gcd = extended_gcd_impl(b % a, a, &x1, &y1);

    *x = y1 - (b / a) * x1;
    *y = x1;
    return gcd;
}

void extended_gcd(int a, int b, int result[]) {
    int x = 0;
    int y = 0;
    int gcd = extended_gcd_impl(a, b, &x, &y);
    result[0] = gcd;
    result[1] = x;
    result[2] = y;
}

#include <iostream>
#include <assert.h>

using namespace std;

int gcdExtended(int a, int b, int* x, int* y)
{
    // Base Condition (Special Case)
    if (a == 0) {
        *x = 0;
        *y = 1;
        return b;
    }

    // Call the function recursively
    int x1, y1;
    int gcd = gcdExtended(b % a, a, &x1, &y1);

    // Update x1 and y1 using results of recursive call
    *x = y1 - (b / a) * x1;
    *y = x1;

    return gcd;
}

int main()
{
    int x, y, a = 60, b = 15;
    int g = gcdExtended(a, b, &x, &y);

    assert(g == 15);

    // Test the function
    cout << "gcd(" << a << ", " << b << ") = " << g << endl;

    return 0;
}

public class ExtendedEuclidean {
    public static int[] extendedGcd(int a, int b) {
        if (a == b) {
            return new int[]{Math.abs(a), 1, 0};
        }
        if (a == 0) {
            return new int[]{Math.abs(b), 0, b >= 0 ? 1 : -1};
        }

        int[] next = extendedGcd(b % a, a);
        int gcd = next[0];
        int x1 = next[1];
        int y1 = next[2];
        int x = y1 - (b / a) * x1;
        int y = x1;
        return new int[]{gcd, x, y};
    }
}

fun extendedGcd(a: Int, b: Int): IntArray {
    if (a == b) {
        return intArrayOf(kotlin.math.abs(a), 1, 0)
    }
    if (b == 0) {
        return intArrayOf(kotlin.math.abs(a), if (a >= 0) 1 else -1, 0)
    }

    val next = extendedGcd(b, a % b)
    val gcd = next[0]
    val x = next[2]
    val y = next[1] - (a / b) * next[2]
    return intArrayOf(gcd, x, y)
}

func extendedGcd(_ a: Int, _ b: Int) -> [Int] {
    if a == b {
        return [abs(a), 1, 0]
    }
    if a == 0 {
        return [abs(b), 0, b >= 0 ? 1 : -1]
    }

    let next = extendedGcd(b % a, a)
    let gcd = next[0]
    let x1 = next[1]
    let y1 = next[2]
    let x = y1 - (b / a) * x1
    let y = x1
    return [gcd, x, y]
}

